    if domain in ALLOWED_REDIRECT_DOMAINS:
        return parsed_url.geturl()
    else:
        raise ValueError("Redirect to unauthorized domain")

def process_user_expression(expr: str) -> str:
    try:
        import math
        import ast
        allowed_globals = {
            '__builtins__': None,
            'math': math
        }
        node = ast.parse(expr, mode='eval')
        if not isinstance(node.body, ast.Expression):
            return "Invalid expression"
        result = eval(expr, allowed_globals, {})
        return str(result)
    except Exception as e:
        return f"Error: {str(e)}"
